struct Wallet {
    let privateKey: Data
    let publicKey: Data
    let address: String
    
    init() throws {
        let keyPair = try SecKeyGeneratePair([
            kSecAttrKeyType: kSecAttrKeyTypeECSECPrimeRandom,
            kSecAttrKeySizeInBits: 256,
            kSecPrivateKeyAttrs: [
                kSecAttrIsPermanent: true,
                kSecAttrApplicationTag: "com.yourapp.wallet.privatekey"
            ]
        ])
        
