    func signTransaction(_ transaction: Transaction) throws -> Data {
        let transactionData = try transaction.encode()
        let signature = try SecKeyCreateSignature(privateKey, .ecdsaSignatureDigestSHA256, transactionData as CFData)
        return signature as Data
    }
    
    func sendTransaction(_ transaction: Transaction) async throws -> String {
        let transactionData = try transaction.encode()
        let signature = try signTransaction(transaction)
        
        let url = URL(string: "https://api.blockchain.com/tx/send")!
