struct Transaction {
    let from: String
    let to: String
    let amount: Double
    let fee: Double
    let timestamp: Date
    
    func encode() throws -> Data {
        let transactionData = [
            "from": from,
            "to": to,
            "amount": amount,
            "fee": fee,
            "timestamp": timestamp.timeIntervalSince1970
        ]
        
        return try JSONSerialization.data(withJSONObject: transactionData)
    }
}

enum WalletError: Error {
    case keyGenerationFailed
