extension Wallet {
    private func getPrivateKeyData(from key: SecKey) throws -> Data {
        let attributes = SecKeyCopyAttributes(key) as? [String: Any]
        let keyData = attributes?[kSecValueData as String] as? Data
        return keyData ?? Data()
    }
    
    private func getPublicKeyData(from key: SecKey) throws -> Data {
        let publicKeyData = SecKeyCopyExternalRepresentation(key, nil) as? Data
        return publicKeyData ?? Data()
    }
    
    private func generateAddress(from publicKey: Data) throws -> String {
        let hash = SHA256.hash(data: publicKey)
        let address = hash.compactMap { String(format: "%02x", $0) }.joined()
        return "0x" + address.prefix(40)
    }
}

